function solve(grid, k) {
  const m = grid.length;
  const n = grid[0].length;
  const dp = Array.from({ length: m }, () => 
    Array.from({ length: n }, () => Array(k + 1).fill Infinity)
  );
  dp[0][0][0] = 0;

